# 使用 Daft 根据 modality 字段处理不同类型数据

以下是使用 Daft 根据 `modality` 字段对 image 和 text 应用不同 UDF 的方案：

## 方案 1: 使用条件过滤 + 分别处理 + 合并

```python
import daft
from daft import col, DataType
import numpy as np

# 定义 image embedding UDF
@daft.udf(return_dtype=DataType.python())
def image_embedding(image_data):
    # 模拟图像 embedding 处理
    return np.random.rand(512).tolist()

# 定义 text embedding UDF
@daft.udf(return_dtype=DataType.python())
def text_embedding(text_data):
    # 模拟文本 embedding 处理
    return np.random.rand(768).tolist()

# 创建示例数据
df = daft.from_pydict({
    "id": [1, 2, 3, 4],
    "modality": ["image", "text", "image", "text"],
    "image": ["img1.jpg", None, "img3.jpg", None],
    "text": [None, "hello world", None, "daft is great"]
})

# 分别处理不同 modality
image_df = (df
    .where(col("modality") == "image")
    .with_column("embedding", image_embedding(col("image")))
)

text_df = (df
    .where(col("modality") == "text")
    .with_column("embedding", text_embedding(col("text")))
)

# 合并结果
result_df = image_df.concat(text_df)
result_df.show()
```

## 方案 2: 使用单个 UDF 内部判断

```python
import daft
from daft import col, DataType

@daft.udf(return_dtype=DataType.python())
def universal_embedding(modality, image_data, text_data):
    if modality == "image":
        # 处理图像
        return image_embed_fn(image_data)
    elif modality == "text":
        # 处理文本
        return text_embed_fn(text_data)
    else:
        return None

def image_embed_fn(img):
    import numpy as np
    return np.random.rand(512).tolist()

def text_embed_fn(txt):
    import numpy as np
    return np.random.rand(768).tolist()

# 应用统一 UDF
result_df = df.with_column(
    "embedding",
    universal_embedding(col("modality"), col("image"), col("text"))
)
result_df.show()
```

## 方案 3: 使用 when-otherwise 表达式（推荐）

```python
import daft
from daft import col, DataType

@daft.udf(return_dtype=DataType.python())
def embed_image(image_path):
    import numpy as np
    # 实际场景：加载图像并生成 embedding
    return np.random.rand(512).tolist()

@daft.udf(return_dtype=DataType.python())
def embed_text(text):
    import numpy as np
    # 实际场景：使用文本模型生成 embedding
    return np.random.rand(768).tolist()

# 使用条件表达式
result_df = df.with_column(
    "embedding",
    daft.when(col("modality") == "image")
        .then(embed_image(col("image")))
        .otherwise(embed_text(col("text")))
)
result_df.show()
```

## 方案 4: 实际应用示例（使用真实模型）

```python
import daft
from daft import col, DataType
from PIL import Image
import torch

@daft.udf(return_dtype=DataType.python())
def clip_image_embedding(image_path):
    from transformers import CLIPProcessor, CLIPModel
    model = CLIPModel.from_pretrained("openai/clip-vit-base-patch32")
    processor = CLIPProcessor.from_pretrained("openai/clip-vit-base-patch32")

    image = Image.open(image_path)
    inputs = processor(images=image, return_tensors="pt")
    with torch.no_grad():
        embedding = model.get_image_features(**inputs)
    return embedding.squeeze().numpy().tolist()

@daft.udf(return_dtype=DataType.python())
def clip_text_embedding(text):
    from transformers import CLIPProcessor, CLIPModel
    model = CLIPModel.from_pretrained("openai/clip-vit-base-patch32")
    processor = CLIPProcessor.from_pretrained("openai/clip-vit-base-patch32")

    inputs = processor(text=[text], return_tensors="pt", padding=True)
    with torch.no_grad():
        embedding = model.get_text_features(**inputs)
    return embedding.squeeze().numpy().tolist()

# 应用
result_df = df.with_column(
    "embedding",
    daft.when(col("modality") == "image")
        .then(clip_image_embedding(col("image")))
        .when(col("modality") == "text")
        .then(clip_text_embedding(col("text")))
        .otherwise(None)
)
```

## 性能优化建议

1. **批处理**: 对相同 modality 的数据分组批处理
2. **模型缓存**: 在 UDF 外部初始化模型避免重复加载
3. **并行处理**: 利用 Daft 的分布式能力

```python
# 使用资源优化的 UDF
@daft.udf(return_dtype=DataType.python(), num_gpus=1)
def optimized_embedding(modality, image, text):
    # 模型会在 worker 级别缓存
    global _model_cache
    if '_model_cache' not in globals():
        _model_cache = load_models()

    if modality == "image":
        return _model_cache['image_model'].encode(image)
    else:
        return _model_cache['text_model'].encode(text)
```

**推荐使用方案 3（when-otherwise）**，代码清晰且性能良好。

# 修复 TIMESTAMPTZ 数据类型错误

问题是 `TIMESTAMPTZ` (DataType 26) 需要特定格式的时间戳，不能直接插入字符串。需要转换为整数时间戳（毫秒）。

## 解决方案：正确处理 TIMESTAMPTZ 字段

```python
%%time
from datetime import datetime
from typing import Iterator
import json

# 配置参数
MILVUS_CONFIG = {
    'host': '127.0.0.1',
    'port': '19530',
    'db_name': 'multimodal_db',
    'col_name': 'multimodal_retrieval',
    'batch_size': 5000
}

def convert_to_timestamp(value):
    """
    将各种时间格式转换为毫秒时间戳

    Args:
        value: 时间值（字符串、整数、datetime对象等）

    Returns:
        int: 毫秒级时间戳
    """
    from datetime import datetime
    import time

    if value is None:
        return int(time.time() * 1000)

    # 如果已经是整数，检查是否是合理的时间戳
    if isinstance(value, (int, float)):
        # 如果是秒级时间戳（10位）
        if value < 10000000000:
            return int(value * 1000)
        # 如果是毫秒级时间戳（13位）
        elif value < 10000000000000:
            return int(value)
        # 如果是微秒级时间戳（16位）
        else:
            return int(value / 1000)

    # 如果是字符串，尝试解析
    if isinstance(value, str):
        try:
            # 处理 ISO 8601 格式
            if 'T' in value:
                # 移除时区标识符
                value = value.replace('Z', '+00:00')
                dt = datetime.fromisoformat(value)
                return int(dt.timestamp() * 1000)
            # 处理其他格式
            else:
                dt = datetime.strptime(value, "%Y-%m-%d %H:%M:%S")
                return int(dt.timestamp() * 1000)
        except Exception as e:
            print(f"[WARNING] Failed to parse timestamp '{value}': {e}, using current time")
            return int(time.time() * 1000)

    # 如果是 datetime 对象
    if isinstance(value, datetime):
        return int(value.timestamp() * 1000)

    # 其他情况返回当前时间
    print(f"[WARNING] Unknown timestamp format: {type(value)}, using current time")
    return int(time.time() * 1000)


def map_partition_insert_fixed(iterator: Iterator) -> Iterator:
    """
    修复 TIMESTAMPTZ 类型的版本
    """
    from pymilvus import connections, Collection, db, DataType
    import numpy as np

    # 建立连接
    try:
        connections.connect(
            alias="default",
            host=MILVUS_CONFIG['host'],
            port=MILVUS_CONFIG['port']
        )
        db.using_database(MILVUS_CONFIG['db_name'])
        collection = Collection(name=MILVUS_CONFIG['col_name'])
    except Exception as e:
        print(f"[ERROR] Connection failed: {e}")
        yield {"partition_total": 0, "status": "connection_error"}
        return

    # 获取 schema 信息
    field_names = []
    field_types = {}

    for field in collection.schema.fields:
        if field.name != "text_sparse_vector":
            field_names.append(field.name)
            field_types[field.name] = field.dtype

    print(f"[INFO] Fields: {field_names}")
    print(f"[INFO] Field types: {field_types}")

    # 批次数据
    batch_data = {name: [] for name in field_names}
    batch_id = 0
    total_inserted = 0
    total_processed = 0
    batch_size = MILVUS_CONFIG['batch_size']

    try:
        for row in iterator:
            total_processed += 1

            # 处理每个字段
            for field_name in field_names:
                if hasattr(row, field_name):
                    value = getattr(row, field_name)
                    field_type = field_types.get(field_name)

                    # 根据字段类型进行转换
                    if field_type == DataType.TIMESTAMPTZ:
                        # 特殊处理时间戳
                        value = convert_to_timestamp(value)

                    elif field_type == DataType.JSON:
                        # JSON 字段
                        if isinstance(value, str):
                            try:
                                value = json.loads(value)
                            except:
                                value = {}
                        elif value is None:
                            value = {}

                    elif field_type == DataType.VARCHAR:
                        # 字符串字段
                        value = str(value) if value is not None else ""

                    elif field_type == DataType.INT16:
                        # 整数字段
                        value = int(value) if value is not None else 0

                    elif field_type == DataType.ARRAY:
                        # 数组字段（如 image_wh）
                        if value is None:
                            value = [0, 0]
                        elif isinstance(value, str):
                            try:
                                value = json.loads(value)
                            except:
                                value = [0, 0]
                        elif not isinstance(value, list):
                            value = list(value)

                    elif field_type == DataType.FLOAT_VECTOR:
                        # 向量字段
                        if value is not None:
                            if isinstance(value, np.ndarray):
                                value = value.tolist()
                            elif not isinstance(value, list):
                                value = list(value)
                        else:
                            value = []

                    batch_data[field_name].append(value)
                else:
                    # 字段不存在，填充默认值
                    field_type = field_types.get(field_name)

                    if field_type == DataType.TIMESTAMPTZ:
                        batch_data[field_name].append(int(datetime.now().timestamp() * 1000))
                    elif field_type == DataType.JSON:
                        batch_data[field_name].append({})
                    elif field_type == DataType.INT16:
                        batch_data[field_name].append(0)
                    elif field_type == DataType.ARRAY:
                        batch_data[field_name].append([0, 0])
                    elif field_type == DataType.FLOAT_VECTOR:
                        batch_data[field_name].append([])
                    else:
                        batch_data[field_name].append("")

            # 批量插入
            if len(batch_data["id"]) >= batch_size:
                try:
                    entities = [batch_data[name] for name in field_names]

                    # 调试：打印第一条数据的类型
                    if batch_id == 0:
                        print("[DEBUG] First record types:")
                        for i, name in enumerate(field_names):
                            if entities[i]:
                                print(f"  {name}: {type(entities[i][0])} = {entities[i][0]}")

                    collection.insert(entities)
                    num_inserted = len(batch_data["id"])
                    total_inserted += num_inserted

                    print(f"{datetime.now()} - Batch {batch_id}: {num_inserted} records, Total: {total_inserted}")

                    # 清空批次
                    for key in batch_data:
                        batch_data[key].clear()

                    batch_id += 1

                except Exception as e:
                    print(f"[ERROR] Failed to insert batch {batch_id}: {e}")
                    import traceback
                    traceback.print_exc()

                    # 打印导致错误的数据类型
                    print("[DEBUG] Problematic batch data types:")
                    for name in field_names:
                        if batch_data[name]:
                            print(f"  {name}: {type(batch_data[name][0])}")

                    # 清空批次，继续处理
                    for key in batch_data:
                        batch_data[key].clear()

        # 插入剩余数据
        if len(batch_data["id"]) > 0:
            try:
                entities = [batch_data[name] for name in field_names]
                collection.insert(entities)

                num_inserted = len(batch_data["id"])
                total_inserted += num_inserted

                print(f"{datetime.now()} - Final Batch: {num_inserted} records, Total: {total_inserted}")
            except Exception as e:
                print(f"[ERROR] Failed to insert final batch: {e}")
                import traceback
                traceback.print_exc()

        collection.flush()
        print(f"[SUCCESS] Partition: {total_inserted}/{total_processed} records")

        yield {
            "partition_total": total_inserted,
            "partition_processed": total_processed,
            "partition_batches": batch_id + 1,
            "status": "success"
        }

    except Exception as e:
        print(f"[ERROR] Partition failed: {e}")
        import traceback
        traceback.print_exc()

        yield {
            "partition_total": total_inserted,
            "partition_processed": total_processed,
            "partition_batches": batch_id,
            "status": "error",
            "error": str(e)
        }

    finally:
        try:
            connections.disconnect(alias="default")
        except:
            pass

# 执行
result_rdd = input_df.repartition(50).rdd.mapPartitions(map_partition_insert_fixed)
results = result_rdd.collect()

# 统计
total_inserted = sum(r.get("partition_total", 0) for r in results)
total_processed = sum(r.get("partition_processed", 0) for r in results)
print(f"\n[FINAL] Inserted: {total_inserted}/{total_processed}")
```

## 简化版本：使用 foreachPartition

```python
%%time

def insert_partition_fixed(iterator):
    """简化版本，正确处理 TIMESTAMPTZ"""
    from pymilvus import connections, Collection, db, DataType
    import json
    from datetime import datetime
    import time

    # 时间戳转换函数
    def to_timestamp_ms(value):
        if value is None:
            return int(time.time() * 1000)
        if isinstance(value, (int, float)):
            return int(value * 1000) if value < 10000000000 else int(value)
        if isinstance(value, str):
            try:
                value = value.replace('Z', '+00:00')
                dt = datetime.fromisoformat(value)
                return int(dt.timestamp() * 1000)
            except:
                return int(time.time() * 1000)
        return int(time.time() * 1000)

    # 连接
    connections.connect(alias="default", host='127.0.0.1', port='19530')
    db.using_database('multimodal_db')
    collection = Collection(name='multimodal_retrieval')

    # 获取字段信息
    field_names = []
    field_types = {}
    for field in collection.schema.fields:
        if field.name != "text_sparse_vector":
            field_names.append(field.name)
            field_types[field.name] = field.dtype

    batch_data = {name: [] for name in field_names}
    batch_size = 5000
    batch_id = 0
    total = 0

    try:
        for row in iterator:
            for field_name in field_names:
                value = getattr(row, field_name, None)
                field_type = field_types[field_name]

                # 类型转换
                if field_type == DataType.TIMESTAMPTZ:
                    value = to_timestamp_ms(value)
                elif field_type == DataType.JSON:
                    if isinstance(value, str):
                        value = json.loads(value) if value else {}
                    elif value is None:
                        value = {}
                elif field_type == DataType.VARCHAR:
                    value = str(value) if value is not None else ""
                elif field_type == DataType.INT16:
                    value = int(value) if value is not None else 0
                elif field_type == DataType.ARRAY:
                    if value is None:
                        value = [0, 0]
                    elif isinstance(value, str):
                        value = json.loads(value)

                batch_data[field_name].append(value)

            # 批量插入
            if len(batch_data["id"]) >= batch_size:
                entities = [batch_data[name] for name in field_names]
                collection.insert(entities)
                total += len(batch_data["id"])
                print(f"{datetime.now()} - Batch {batch_id}: {len(batch_data['id'])}, Total: {total}")

                for key in batch_data:
                    batch_data[key].clear()
                batch_id += 1

        # 剩余数据
        if len(batch_data["id"]) > 0:
            entities = [batch_data[name] for name in field_names]
            collection.insert(entities)
            total += len(batch_data["id"])
            print(f"{datetime.now()} - Final: {len(batch_data['id'])}, Total: {total}")

        collection.flush()
        print(f"[SUCCESS] Total: {total}")

    except Exception as e:
        print(f"[ERROR] {e}")
        import traceback
        traceback.print_exc()

    finally:
        connections.disconnect(alias="default")

# 执行
input_df.repartition(50).rdd.foreachPartition(insert_partition_fixed)
print("[DONE]")
```

