## 关键修复点

1. **TIMESTAMPTZ 必须是整数毫秒时间戳**：不能是字符串
2. **转换逻辑**：
   - ISO 8601 字符串 → 解析后转换为毫秒时间戳
   - 秒级时间戳 → 乘以 1000
   - 微秒级时间戳 → 除以 1000
3. **使用 `DataType` 枚举判断字段类型**：更准确
4. **添加调试信息**：打印第一条记录的类型便于排查

这样就能正确插入 `TIMESTAMPTZ` 字段了！

问题现在很明确了：即使 `time_stamp` 已经是 `int` 类型，PyMilvus 仍然报错 "Unsupported data type: 26"。这是因为 PyMilvus 客户端版本可能不完全支持 `TIMESTAMPTZ` 类型，或者需要特殊的插入方式。

# 解决方案：检查并使用正确的数据格式

```python
%%time
from datetime import datetime
from typing import Iterator
import json

# 配置参数
MILVUS_CONFIG = {
    'host': '127.0.0.1',
    'port': '19530',
    'db_name': 'multimodal_db',
    'col_name': 'multimodal_retrieval',
    'batch_size': 5000
}

def insert_partition_fixed(iterator):
    """修复 TIMESTAMPTZ 问题的版本"""
    from pymilvus import connections, Collection, db, DataType
    import json
    from datetime import datetime
    import time

    # 连接
    connections.connect(alias="default", host='127.0.0.1', port='19530')
    db.using_database('multimodal_db')
    collection = Collection(name='multimodal_retrieval')

    # 获取字段信息
    field_names = []
    field_types = {}

    for field in collection.schema.fields:
        if field.name != "text_sparse_vector":
            field_names.append(field.name)
            field_types[field.name] = field.dtype
            print(f"Field: {field.name}, Type: {field.dtype} ({field.dtype.value})")

    batch_data = {name: [] for name in field_names}
    batch_size = 5000
    batch_id = 0
    total = 0

    try:
        for row in iterator:
            for field_name in field_names:
                value = getattr(row, field_name, None)
                field_type = field_types[field_name]

                # 类型转换
                if field_type == DataType.TIMESTAMPTZ:
                    # TIMESTAMPTZ 需要毫秒时间戳
                    if isinstance(value, str):
                        try:
                            dt = datetime.fromisoformat(value.replace('Z', '+00:00'))
                            value = int(dt.timestamp() * 1000)
                        except:
                            value = int(time.time() * 1000)
                    elif isinstance(value, (int, float)):
                        if value < 10000000000:  # 秒级时间戳
                            value = int(value * 1000)
                        else:
                            value = int(value)
                    else:
                        value = int(time.time() * 1000)

                    # 确保是 Python int 而不是 numpy.int64
                    value = int(value)

                elif field_type == DataType.JSON:
                    if isinstance(value, str):
                        value = json.loads(value) if value else {}
                    elif value is None:
                        value = {}

                elif field_type == DataType.VARCHAR:
                    value = str(value) if value is not None else ""

                elif field_type == DataType.INT16:
                    value = int(value) if value is not None else 0

                elif field_type == DataType.ARRAY:
                    if value is None:
                        value = [0, 0]
                    elif isinstance(value, str):
                        value = json.loads(value)
                    # 确保数组元素是正确的类型
                    value = [int(x) for x in value]

                elif field_type == DataType.FLOAT_VECTOR:
                    if value is not None:
                        # 确保是 Python list，不是 numpy array
                        if hasattr(value, 'tolist'):
                            value = value.tolist()
                        # 确保是 float 类型
                        value = [float(x) for x in value]
                    else:
                        value = []

                batch_data[field_name].append(value)

            # 批量插入
            if len(batch_data["id"]) >= batch_size:
                entities = [batch_data[name] for name in field_names]

                # 调试第一批
                if batch_id == 0:
                    print("\n[DEBUG] First batch sample:")
                    for i, name in enumerate(field_names):
                        if entities[i]:
                            sample_val = entities[i][0]
                            print(f"  {name}: type={type(sample_val)}, value={sample_val if name != 'mm_embedding' else '[...]'}")

                try:
                    collection.insert(entities)
                    total += len(batch_data["id"])
                    print(f"{datetime.now()} - Batch {batch_id}: {len(batch_data['id'])}, Total: {total}")
                except Exception as e:
                    print(f"[ERROR] Batch {batch_id} failed: {e}")
                    # 尝试逐个插入以找出问题数据
                    for idx in range(len(batch_data["id"])):
                        single_entities = [[batch_data[name][idx]] for name in field_names]
                        try:
                            collection.insert(single_entities)
                            total += 1
                        except Exception as e2:
                            print(f"[ERROR] Row {idx} failed: {e2}")
                            print(f"  Problematic data:")
                            for j, name in enumerate(field_names):
                                print(f"    {name}: {type(single_entities[j][0])} = {single_entities[j][0]}")
                            break

                for key in batch_data:
                    batch_data[key].clear()
                batch_id += 1

        # 剩余数据
        if len(batch_data["id"]) > 0:
            entities = [batch_data[name] for name in field_names]
            try:
                collection.insert(entities)
                total += len(batch_data["id"])
                print(f"{datetime.now()} - Final: {len(batch_data['id'])}, Total: {total}")
            except Exception as e:
                print(f"[ERROR] Final batch failed: {e}")

        collection.flush()
        print(f"[SUCCESS] Total: {total}")

    except Exception as e:
        print(f"[ERROR] {e}")
        import traceback
        traceback.print_exc()

    finally:
        connections.disconnect(alias="default")

