## 方案 2：检查 PyMilvus 版本并使用字符串格式

如果问题持续，可能是 PyMilvus 版本不支持 TIMESTAMPTZ，尝试使用 VARCHAR 存储时间戳：

```python
# 临时解决方案：将 time_stamp 转换为字符串
def insert_partition_workaround(iterator):
    """使用字符串格式的时间戳"""
    from pymilvus import connections, Collection, db, DataType
    import json
    from datetime import datetime

    connections.connect(alias="default", host='127.0.0.1', port='19530')
    db.using_database('multimodal_db')
    collection = Collection(name='multimodal_retrieval')

    # 检查 PyMilvus 版本
    import pymilvus
    print(f"PyMilvus version: {pymilvus.__version__}")

    field_names = []
    field_types = {}

    for field in collection.schema.fields:
        if field.name != "text_sparse_vector":
            field_names.append(field.name)
            field_types[field.name] = field.dtype

    batch_data = {name: [] for name in field_names}
    batch_size = 5000
    batch_id = 0
    total = 0

    try:
        for row in iterator:
            for field_name in field_names:
                value = getattr(row, field_name, None)
                field_type = field_types[field_name]

                # 特殊处理 time_stamp
                if field_name == "time_stamp":
                    # 尝试不同的格式
                    if isinstance(value, str):
                        # 保持字符串格式
                        value = value
                    elif isinstance(value, (int, float)):
                        # 转换为 ISO 格式字符串
                        try:
                            dt = datetime.fromtimestamp(value / 1000 if value > 10000000000 else value)
                            value = dt.isoformat()
                        except:
                            value = datetime.now().isoformat()
                    else:
                        value = datetime.now().isoformat()

                elif field_type == DataType.JSON:
                    if isinstance(value, str):
                        value = json.loads(value) if value else {}
                    elif value is None:
                        value = {}

                elif field_type == DataType.VARCHAR:
                    value = str(value) if value is not None else ""

                elif field_type == DataType.INT16:
                    value = int(value) if value is not None else 0

                elif field_type == DataType.ARRAY:
                    if value is None:
                        value = [0, 0]
                    elif isinstance(value, str):
                        value = json.loads(value)
                    value = [int(x) for x in value]

                elif field_type == DataType.FLOAT_VECTOR:
                    if value is not None:
                        if hasattr(value, 'tolist'):
                            value = value.tolist()
                        value = [float(x) for x in value]
                    else:
                        value = []

                batch_data[field_name].append(value)

            if len(batch_data["id"]) >= batch_size:
                entities = [batch_data[name] for name in field_names]

                try:
                    collection.insert(entities)
                    total += len(batch_data["id"])
                    print(f"{datetime.now()} - Batch {batch_id}: {len(batch_data['id'])}, Total: {total}")
                except Exception as e:
                    print(f"[ERROR] Batch {batch_id} failed: {e}")
                    print(f"[DEBUG] time_stamp sample: {batch_data['time_stamp'][0]} (type: {type(batch_data['time_stamp'][0])})")

                for key in batch_data:
                    batch_data[key].clear()
                batch_id += 1

        if len(batch_data["id"]) > 0:
            entities = [batch_data[name] for name in field_names]
            collection.insert(entities)
            total += len(batch_data["id"])

        collection.flush()
        print(f"[SUCCESS] Total: {total}")

    except Exception as e:
        print(f"[ERROR] {e}")
        import traceback
        traceback.print_exc()

    finally:
        connections.disconnect(alias="default")

input_df.repartition(50).rdd.foreachPartition(insert_partition_workaround)
